INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (1, 'Heavy forest, open valley and meadows, rugged mountains and hills, ridges, rivers, lakes...everything possible for almost any animal is here to survive and survive and flourish away from humans...', 'Spring', 2021, 5, '05/31/2021', '1:00am PST');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (2, 'The Place this occurred is just inside the city limits of Woodsfield, Ohio. The town is very small, but the sighting did occur with in a few hundred feet of houses. It had been and was snowing very heavily that night. The creatures tracks came down off of a very steep embankment and then continued across SR 78. We later found out that on the bank there is a natural spring that flows year round. South Eastern Ohio is a very hilly place. Very much like the whole of West Virginia.', 'Winter', 1994, 2, NULL, 'Mid/Late Febuary 1994. It was about 10:00pm on a week night. It was snowing.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (3, 'heavy forrest, almost directly behind the house on the opposite side of the road from the parking area...nearly to the top of the ridge there', 'Summer', 1983, 8, NULL, '1983 sighting was first light, very warm. 2010 sighting, around 6 pm, very warm, clear.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (4, 'Heavily wooded, fairly remote.', 'Summer', 1982, 7, NULL, 'It was dusk, the sun was setting..estimate time was around 8 PM.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (5, 'The environment is a decidious/ coniferous forest with mostly oak, maple and other hardwood trees previlent with pockets of large white pines.  To the south and east  were draws that went down into creek bottoms while the north and south were dense overgrowth and forest.  The sighting was from the road that went around the edges of the state park.', 'Summer', 2009, 7, NULL, 'The sighting occurred  during mid afternoon with sunny conditions in a forested area.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (6, 'Mixed Swamp. creeks, dry land.', 'Winter', 1991, 1, '11', 'We found it on a Friday, early morning.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (7, 'It was forested with,mostly red firs.,and some cedar groves here and there.There were also one or two ponds close to our area.The mountain also had natural water springs throughout it.There was also a lot of brush in some areas.', 'Summer', 1963, 6, '10', 'This incident occurred between 10am and11am.The skyline was mostly clear.Only a few clouds.The air t');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (8, 'This area has water on all four sides from streams which makes it literally an island. It is thick with woods and abundant wildlife. The thing with this area is it is close to the George Washington National Forest.', 'Spring', 2014, 4, '3', 'Around 4:00 am');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (9, 'Fields, livestock, swamp, creeks,', 'Winter', 2017, 1, '1/15/2017', '12 noon. Overcast and about to storm.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (10, 'One the right side of the road there are storage building and on the left is the family''s home.  But not far behind all of that on both side are woods and mountains.  It''s not far from Mill Creek.', 'Fall', 2003, 11, '27', 'It was a clear night, but very cold.  It was around 11:30pm.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (11, 'Mt. Saint Helens was erupting.', 'Spring', 1980, 5, '18', 'Morning. Sulfur smell.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (12, 'Logged area with plenty of Doug fir, Larch and Ponderosa pine. Some Cottonwoods and aspen in the seasonal streams on either side of the property. Also, lots of shrubby understory; nine barks, spirea, serviceberry and snowberry.', 'Summer', 2013, 7, NULL, '2 a.m. no moon, dark. Hot and dry no clouds.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (13, 'The environment is a small field, with trees and taller bushes.', 'Fall', 2015, 11, '5', '60 degrees, sunny at 4:12 pm');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (14, 'Heavily wooded area with a small creek.', 'Summer', 2021, 7, '9th', 'The print was found at approximately 10:00 A.M. sunny daylight conditions.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (15, 'Many many pine trees and woods and a lake w/ many cows.', 'Summer', 1984, 7, NULL, 'It was around 8:00 getting dark, as I ran the sun hit me in the back.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (16, 'On the edge of the Meramac River with some open pasture and heavy forest from the edge of the campsite on down river for several miles. Lots of caves in the area. Oak, Hickory, Black Walnut, Wild Plum, Mulberry, Paw Paw, Wild Cherry, Blackberry ect.', 'Summer', 1982, 6, NULL, 'Started about 20 minutes before dark and lasted about an hour after dark.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (17, 'This thing was standing on a concrete bridge, pulling leaves, or something from the branches of trees that grow up from the creek bank below the bridge.', 'Winter', 2001, 12, 'don''t remember', 'about 3am');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (18, 'The land area, was an old timers style coal mining area.', 'Winter', 2014, 2, '17', 'The Tracks had to been made over night Feb 16-17 2014.');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (19, 'Open sage brush/grass on mountain side. Pine groves running in the gulches of the mountain and occasionally in the open areas. Cypress trees in the open areas as well.', 'Fall', 2012, 9, '9/23/12', '7:30 AM, Clear');
INSERT INTO ENVIRONMENT (Environment_ID, Environment_Description, Season, Year, Month, Date_Text, Time_And_Conditions) VALUES (20, 'Dense trees, large hills, ponds, less travelled roads.', 'Fall', 2002, 9, '7', 'Both Day and Night');
